// ---------- Google Form Submit ----------
async function submitGoogleForm({
  name,
  phone,
  email,
  message,
  pagePath,
  campaign,
  id,
}: {
  name: string;
  phone: string;
  email: string;
  message: string;
  pagePath: string;
  campaign: string;
  id: string;
}) {
  const formUrl = `https://docs.google.com/forms/d/e/${id}/formResponse`;

  const formData = new URLSearchParams();
  formData.append("entry.466204223", name);
  formData.append("entry.32405555", phone);
  formData.append("entry.2122071872", email);
  formData.append("entry.176904452", message);
  formData.append("entry.1591426887", pagePath);
  formData.append("entry.688569624", campaign);

  try {
    await fetch(formUrl, {
      method: "POST",
      mode: "no-cors",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: formData.toString(),
    });
    return true;
  } catch (err) {
    console.error("Error submitting form:", err);
    return false;
  }
}

